/// <summary>
/// Determines whether an active workflow template for purchase agreements exists.
/// </summary>
/// <returns>true, if an active workflow template for purchase agreements exists; otherwise, false.</returns>
public static boolean activeWorkflowTemplateExists()
{
    boolean isWfActive = next activeWorkflowTemplateExists();

    //NS, DLT, actiavte WF control, 09-july-25
    if(!isWfActive && ETGACFParameters::find().EnablePurchaseAgreementWF)
    {
        isWfActive = WorkflowTable::findActiveTemplate(workFlowTypeStr(ETGPurchAgreementType)).RecId;
    }
    //NE, DLT, actiavte WF control, 09-july-25

    return isWfActive;
}
